const express = require('express');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const redis = require('redis');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

const twilioClient = twilio('TWILIO_ACCOUNT_SID', 'TWILIO_AUTH_TOKEN');
const redisClient = redis.createClient();

const generateCode = () => Math.floor(100000 + Math.random() * 900000).toString();

const sendSMS = (phoneNumber, code) => {
  return twilioClient.messages.create({
    body: `Your verification code is ${code}`,
    from: 'TWILIO_PHONE_NUMBER',
    to: phoneNumber
  });
};

app.post('/request-code', (req, res) => {
  const { phoneNumber } = req.body;
  const code = generateCode();
  const userKey = `user:${phoneNumber}`;
  const attemptsKey = `attempts:${phoneNumber}`;

  redisClient.setex(userKey, 600, code);
  redisClient.set(attemptsKey, 0, 'EX', 600);

  sendSMS(phoneNumber, code)
    .then(() => res.status(200).send('Code sent'))
    .catch(err => res.status(500).send('Error sending SMS'));
});

app.post('/verify-code', (req, res) => {
  const { phoneNumber, code } = req.body;
  const userKey = `user:${phoneNumber}`;
  const attemptsKey = `attempts:${phoneNumber}`;

  redisClient.get(userKey, (err, storedCode) => {
    if (err) return res.status(500).send('Internal error');
    if (!storedCode) return res.status(400).send('Code expired or invalid');

    redisClient.get(attemptsKey, (err, attempts) => {
      if (err) return res.status(500).send('Internal error');
      if (parseInt(attempts) >= 10) return res.status(403).send('Too many attempts');

      if (storedCode === code) {
        redisClient.del(userKey);
        redisClient.del(attemptsKey);
        return res.status(200).send('Access granted');
      } else {
        redisClient.incr(attemptsKey);
        return res.status(400).send('Incorrect code');
      }
    });
  });
});

app.listen(3000, () => console.log('Server running on port 3000'));